import { requireZernioAuth } from "../_shared/zernioAuth.ts";
import { zernioFetch } from "../_shared/zernioClient.ts";
import { zernioJson, zernioOptions } from "../_shared/zernioHttp.ts";
import { canAccessScope, canPublishOrg, type ZernioScope } from "../_shared/zernioRbac.ts";

type PlatformTarget = { platform: string; accountId: string };

type CreatePostBody = {
  scope?: ZernioScope;
  content?: string;
  platforms?: PlatformTarget[];
  publish_now?: boolean;
  scheduled_for?: string;
  timezone?: string;
  media_urls?: string[];
};

export default async function handler(req: Request): Promise<Response> {
  if (req.method === "OPTIONS") return zernioOptions(req);
  if (req.method !== "POST") return zernioJson(req, 405, { ok: false, error: "Method not allowed" });

  const auth = await requireZernioAuth(req);
  if (auth instanceof Response) return auth;

  let body: CreatePostBody;
  try {
    body = await req.json();
  } catch {
    return zernioJson(req, 400, { ok: false, error: "JSON inválido" });
  }

  const scope = body.scope === "org" ? "org" : body.scope === "personal" ? "personal" : null;
  const content = (body.content ?? "").trim();
  const platforms = body.platforms ?? [];
  const publishNow = body.publish_now === true;
  const scheduledFor = (body.scheduled_for ?? "").trim() || null;
  const timezone = (body.timezone ?? "America/Santiago").trim();
  const mediaUrls = Array.isArray(body.media_urls) ? body.media_urls.filter(Boolean) : [];

  if (!scope) return zernioJson(req, 400, { ok: false, error: "scope debe ser org o personal" });
  if (!content) return zernioJson(req, 400, { ok: false, error: "El contenido es requerido" });
  if (!platforms.length) return zernioJson(req, 400, { ok: false, error: "Selecciona al menos una cuenta" });

  if (scope === "org" && !canPublishOrg(auth.role)) {
    return zernioJson(req, 403, { ok: false, error: "No puedes publicar en cuentas de la automotora" });
  }
  if (!canAccessScope(scope, auth.role)) {
    return zernioJson(req, 403, { ok: false, error: "Sin permiso para este ámbito" });
  }

  const accountIds = platforms.map((p) => p.accountId);
  let accountsQuery = auth.admin
    .from("zernio_accounts")
    .select("zernio_account_id, platform, scope, user_id, status")
    .eq("tenant_id", auth.tenantId)
    .eq("scope", scope)
    .eq("status", "active")
    .in("zernio_account_id", accountIds);

  if (scope === "personal") {
    accountsQuery = accountsQuery.eq("user_id", auth.userId);
  }

  const { data: allowedAccounts, error: accErr } = await accountsQuery;
  if (accErr) return zernioJson(req, 500, { ok: false, error: accErr.message });
  if (!allowedAccounts?.length || allowedAccounts.length !== accountIds.length) {
    return zernioJson(req, 403, { ok: false, error: "Una o más cuentas no están autorizadas" });
  }

  const zernioPlatforms = platforms.map((p) => ({
    platform: p.platform,
    accountId: p.accountId,
  }));

  const localStatus = publishNow ? "publishing" : scheduledFor ? "scheduled" : "draft";

  const { data: localRow, error: insertErr } = await auth.admin
    .from("zernio_posts")
    .insert({
      tenant_id: auth.tenantId,
      scope,
      created_by: auth.userId,
      content,
      media_urls: mediaUrls,
      platforms: zernioPlatforms,
      scheduled_for: scheduledFor,
      timezone,
      status: localStatus,
    })
    .select("id")
    .single();

  if (insertErr) return zernioJson(req, 500, { ok: false, error: insertErr.message });

  try {
    const zernioBody: Record<string, unknown> = {
      content,
      platforms: zernioPlatforms,
      timezone,
    };
    if (mediaUrls.length) zernioBody.mediaUrls = mediaUrls;
    if (publishNow) {
      zernioBody.publishNow = true;
    } else if (scheduledFor) {
      zernioBody.scheduledFor = scheduledFor;
    }

    const created = await zernioFetch<{ post?: { _id?: string }; _id?: string }>("/posts", {
      method: "POST",
      body: zernioBody,
    });

    const zernioPostId = created.post?._id ?? created._id ?? null;
    const finalStatus = publishNow ? "published" : scheduledFor ? "scheduled" : "draft";

    await auth.admin
      .from("zernio_posts")
      .update({
        zernio_post_id: zernioPostId,
        status: finalStatus,
        published_at: publishNow ? new Date().toISOString() : null,
        updated_at: new Date().toISOString(),
      })
      .eq("id", localRow.id);

    return zernioJson(req, 200, {
      ok: true,
      post_id: localRow.id,
      zernio_post_id: zernioPostId,
      status: finalStatus,
    });
  } catch (e) {
    await auth.admin
      .from("zernio_posts")
      .update({
        status: "failed",
        last_error: (e as Error).message,
        updated_at: new Date().toISOString(),
      })
      .eq("id", localRow.id);

    return zernioJson(req, 500, { ok: false, error: (e as Error).message });
  }
}

// CORS helper para Edge Functions.
//
// En producción, setear el secret `ALLOWED_ORIGINS` en Supabase con la lista
// de orígenes separados por coma (ej: "https://app.skalemotors.cl,https://skalemotors.cl").
// Si no está seteado, mantiene el comportamiento legacy (wildcard).
//
// Uso recomendado en handlers:
//   const cors = getCorsHeaders(req);
//   ...new Response(..., { headers: { ...cors } });
//
// Compatibilidad: corsHeaders (constante con `*`) se mantiene para no romper
// las funciones existentes hasta que se migren una a una.

const ALLOWED_HEADERS =
  "authorization, x-client-info, apikey, content-type, x-api-key, x-webhook-token, x-signature, x-hub-signature-256, idempotency-key";
const ALLOWED_METHODS = "GET,POST,OPTIONS";
const MAX_AGE = "86400";

function getAllowedOrigins(): string[] | null {
  const raw = Deno.env.get("ALLOWED_ORIGINS");
  if (!raw) return null;
  return raw.split(",").map((s) => s.trim()).filter(Boolean);
}

const corsBase = {
  Vary: "Origin",
  "Access-Control-Allow-Headers": ALLOWED_HEADERS,
  "Access-Control-Allow-Methods": ALLOWED_METHODS,
  "Access-Control-Max-Age": "600",
} as const;

/** true si no hay lista de orígenes o el Origin del request está permitido */
export function isOriginAllowed(req: Request): boolean {
  const allowed = getAllowedOrigins();
  if (!allowed || allowed.length === 0) return true;
  const origin = req.headers.get("origin");
  return Boolean(origin && allowed.includes(origin));
}

export function getCorsHeaders(req: Request): Record<string, string> {
  const origin = req.headers.get("origin");
  const allowed = getAllowedOrigins();

  if (!allowed || allowed.length === 0) {
    return {
      ...corsBase,
      "Access-Control-Allow-Origin": origin ?? "*",
    };
  }

  if (!origin || !allowed.includes(origin)) {
    // No devolver el primer origen de la lista: el browser bloquea el POST y parece timeout.
    return { ...corsBase };
  }

  return {
    ...corsBase,
    "Access-Control-Allow-Origin": origin,
  };
}

// Constante compartida. Si `ALLOWED_ORIGINS` está seteado en Supabase Secrets,
// usa el primer origen permitido (lockdown CORS). Si no, fallback a `*` (legacy).
// Para validación per-request real (multi-origen con echo del origen del request),
// usar getCorsHeaders(req).
function resolveDefaultAllowOrigin(): string {
  const allowed = getAllowedOrigins();
  if (allowed && allowed.length > 0) return allowed[0];
  return "*";
}

export const corsHeaders = {
  "Access-Control-Allow-Origin": resolveDefaultAllowOrigin(),
  "Vary": "Origin",
  "Access-Control-Allow-Headers": ALLOWED_HEADERS,
  "Access-Control-Allow-Methods": ALLOWED_METHODS,
  "Access-Control-Max-Age": MAX_AGE,
};

import { createClient, type SupabaseClient } from "https://esm.sh/@supabase/supabase-js@2";
import { getCorsHeaders } from "./cors.ts";

export type ZernioAuthContext = {
  userId: string;
  tenantId: string;
  role: string;
  branchId: string | null;
  userClient: SupabaseClient;
  admin: SupabaseClient;
};

function getEnv(name: string): string | null {
  return Deno.env.get(name) ?? null;
}

function authErrorResponse(req: Request, status: number, error: string): Response {
  const cors = getCorsHeaders(req);
  return new Response(JSON.stringify({ ok: false, error }), {
    status,
    headers: { ...cors, "Content-Type": "application/json" },
  });
}

export async function requireZernioAuth(req: Request): Promise<ZernioAuthContext | Response> {
  const authHeader = req.headers.get("authorization") || "";
  if (!authHeader.toLowerCase().startsWith("bearer ")) {
    return authErrorResponse(req, 401, "Missing auth");
  }

  const supabaseUrl = getEnv("SUPABASE_URL") ?? getEnv("PROJECT_URL");
  const anonKey = getEnv("SUPABASE_ANON_KEY");
  const serviceRoleKey = getEnv("SUPABASE_SERVICE_ROLE_KEY") ?? getEnv("SERVICE_ROLE_KEY");
  if (!supabaseUrl || !anonKey || !serviceRoleKey) {
    return authErrorResponse(req, 500, "Missing Supabase env vars");
  }

  const userClient = createClient(supabaseUrl, anonKey, {
    global: { headers: { Authorization: authHeader } },
  });
  const { data: userData, error: userErr } = await userClient.auth.getUser();
  if (userErr || !userData?.user) {
    return authErrorResponse(req, 401, "Invalid auth");
  }

  const admin = createClient(supabaseUrl, serviceRoleKey, { auth: { persistSession: false } });
  const { data: profile, error: profileErr } = await admin
    .from("users")
    .select("id, tenant_id, branch_id, role")
    .eq("id", userData.user.id)
    .maybeSingle();

  if (profileErr || !profile?.tenant_id) {
    return authErrorResponse(req, 403, "Perfil de usuario no encontrado");
  }

  return {
    userId: userData.user.id,
    tenantId: profile.tenant_id,
    role: profile.role ?? "vendedor",
    branchId: profile.branch_id ?? null,
    userClient,
    admin,
  };
}

export type ZernioScope = "org" | "personal";

const ORG_CONNECT_ROLES = new Set(["admin", "gerente", "jefe_jefe"]);
const ORG_PUBLISH_ROLES = new Set(["admin", "gerente", "jefe_jefe", "jefe_sucursal"]);

export function canConnectOrg(role: string | null | undefined): boolean {
  return !!role && ORG_CONNECT_ROLES.has(role);
}

export function canPublishOrg(role: string | null | undefined): boolean {
  return !!role && ORG_PUBLISH_ROLES.has(role);
}

export function canAccessScope(scope: ZernioScope, role: string | null | undefined): boolean {
  if (scope === "personal") return true;
  return canViewOrg(scope, role);
}

export function canViewOrg(_scope: ZernioScope, role: string | null | undefined): boolean {
  return canPublishOrg(role) || canConnectOrg(role);
}

export function canMutateOrgAccounts(role: string | null | undefined): boolean {
  return canConnectOrg(role);
}

const ZERNIO_API_BASE = "https://zernio.com/api/v1";
const ZERNIO_FETCH_TIMEOUT_MS = 12_000;

export async function zernioFetch<T>(
  path: string,
  init?: { method?: string; body?: unknown },
): Promise<T> {
  const apiKey = Deno.env.get("ZERNIO_API_KEY");
  if (!apiKey) {
    throw new Error("ZERNIO_API_KEY no configurada en Supabase Secrets");
  }

  const controller = new AbortController();
  const timeoutId = setTimeout(() => controller.abort(), ZERNIO_FETCH_TIMEOUT_MS);

  let res: Response;
  try {
    res = await fetch(`${ZERNIO_API_BASE}${path}`, {
      method: init?.method ?? "GET",
      headers: {
        Authorization: `Bearer ${apiKey}`,
        "Content-Type": "application/json",
      },
      body: init?.body !== undefined ? JSON.stringify(init.body) : undefined,
      signal: controller.signal,
    });
  } catch (e) {
    if (e instanceof Error && e.name === "AbortError") {
      throw new Error("Zernio tardó demasiado en responder. Intenta de nuevo.");
    }
    throw e;
  } finally {
    clearTimeout(timeoutId);
  }

  const json = await res.json().catch(() => ({}));
  if (!res.ok) {
    const msg =
      (json as { message?: string }).message ??
      (json as { error?: string }).error ??
      res.statusText;
    const code = (json as { code?: string }).code;
    const suffix = code ? ` (${code})` : "";
    throw new Error(
      typeof msg === "string" ? `${msg}${suffix}` : `Error en Zernio API (${res.status})`,
    );
  }
  return json as T;
}
